import React from "react";
import styles from "./authentication.module.css";
import Layout from "../../../components/layout";
import GridLayout from "../../../components/layout/grid-layout";
import AuthenticationForm from "../../../components/checkout page/authentication-form";
import SummaryProduct from "../../../components/checkout page/summary-product";

const Authentication = () => {
  return (
    <Layout>
      <div className="container">
        <GridLayout>
          <div className={styles.left_side}>
            <AuthenticationForm />
          </div>
          <div
            className={styles.right_side}
            style={{
              margin: 0,         // Reset margin
              maxWidth: "none", // Reset max-width
              width: "100%"     // Make it 100% width
            }}
          >
            <SummaryProduct />
          </div>
        </GridLayout>
      </div>
    </Layout>
  );
};

export default Authentication;
